import { useEffect, useState, useCallback, useRef } from 'react';
import {
  Modal,
  ModalBody,
  ModalFooter,
  ModalHeader,
  Button,
  Label,
  Flex,
  FlexItem,
  TextInput,
  Spinner,
  Alert,
} from '@patternfly/react-core';
import { PlayIcon, StopIcon, CheckCircleIcon, ExclamationCircleIcon } from '@patternfly/react-icons';
import {
  ptySpawn,
  ptyWrite,
  ptyKill,
  onPtyOutput,
  onPtyExit,
  ProcessInfo,
  PtyOutput,
  PtyExit,
} from '../lib/rpc';
import type { Feature } from '../state/store';

type UnlistenFn = () => void;

export type TaskExecutionStatus = 'idle' | 'starting' | 'running' | 'success' | 'failed' | 'cancelled';

export type TaskExecutionModalProps = {
  isOpen: boolean;
  task: Feature | null;
  projectPath: string;
  onClose: () => void;
  onComplete: (taskId: string, success: boolean) => void;
};

/**
 * Modal that executes a task using Claude Code via PTY
 * Shows real-time output and allows user interaction
 */
export function TaskExecutionModal({
  isOpen,
  task,
  projectPath,
  onClose,
  onComplete,
}: TaskExecutionModalProps) {
  const [status, setStatus] = useState<TaskExecutionStatus>('idle');
  const [processInfo, setProcessInfo] = useState<ProcessInfo | null>(null);
  const [output, setOutput] = useState<string[]>([]);
  const [input, setInput] = useState('');
  const [error, setError] = useState<string | null>(null);

  const outputRef = useRef<HTMLDivElement>(null);
  const unlistenRef = useRef<UnlistenFn[]>([]);
  const processIdRef = useRef<string | null>(null);

  // Auto-scroll to bottom when output changes
  useEffect(() => {
    if (outputRef.current) {
      outputRef.current.scrollTop = outputRef.current.scrollHeight;
    }
  }, [output]);

  // Cleanup listeners on unmount
  useEffect(() => {
    return () => {
      unlistenRef.current.forEach((unlisten) => unlisten());
      unlistenRef.current = [];
    };
  }, []);

  // Reset state when modal opens with new task
  useEffect(() => {
    if (isOpen && task) {
      setStatus('idle');
      setOutput([]);
      setError(null);
      setInput('');
      setProcessInfo(null);
      processIdRef.current = null;
    }
  }, [isOpen, task?.id]);

  // Build the prompt for Claude Code
  const buildPrompt = useCallback((t: Feature): string => {
    const parts = [
      `Task: ${t.description}`,
    ];

    if (t.steps && t.steps.length > 0) {
      parts.push('');
      parts.push('Steps:');
      t.steps.forEach((step, idx) => {
        parts.push(`${idx + 1}. ${step}`);
      });
    }

    parts.push('');
    parts.push('Please complete this task. When finished, the task will be marked as done.');

    return parts.join('\n');
  }, []);

  // Start execution
  const handleStart = useCallback(async () => {
    if (!task || !projectPath) return;

    setStatus('starting');
    setOutput([]);
    setError(null);

    try {
      // Spawn Claude Code in the project directory
      const info = await ptySpawn('claude', [], projectPath, 40, 120);

      setProcessInfo(info);
      processIdRef.current = info.id;
      setStatus('running');

      setOutput([
        `\x1b[36m╔══════════════════════════════════════════════════════════════╗\x1b[0m\n`,
        `\x1b[36m║  HQ Task Execution                                           ║\x1b[0m\n`,
        `\x1b[36m╚══════════════════════════════════════════════════════════════╝\x1b[0m\n`,
        `\n`,
        `\x1b[33mTask:\x1b[0m ${task.description}\n`,
        `\x1b[33mProject:\x1b[0m ${projectPath}\n`,
        `\n`,
        `\x1b[32m[Starting Claude Code...]\x1b[0m\n`,
        `\n`,
      ]);

      // Setup event listeners
      const unlistenOutput = await onPtyOutput((payload: PtyOutput) => {
        if (payload.id === info.id) {
          setOutput((prev) => [...prev, payload.data]);
        }
      });

      const unlistenExit = await onPtyExit((payload: PtyExit) => {
        if (payload.id === info.id) {
          const exitCode = payload.code;
          const success = exitCode === 0;

          setOutput((prev) => [
            ...prev,
            `\n`,
            success
              ? `\x1b[32m[Task completed successfully (exit code: ${exitCode})]\x1b[0m\n`
              : `\x1b[31m[Task finished with exit code: ${exitCode}]\x1b[0m\n`,
          ]);

          setStatus(success ? 'success' : 'failed');
          processIdRef.current = null;

          // Notify parent
          if (task) {
            onComplete(task.id, success);
          }
        }
      });

      unlistenRef.current = [unlistenOutput, unlistenExit];

      // Wait a moment for Claude to initialize, then send the task prompt
      setTimeout(async () => {
        const prompt = buildPrompt(task);
        try {
          await ptyWrite(info.id, prompt + '\n');
        } catch (writeError) {
          console.error('Failed to send prompt:', writeError);
        }
      }, 1500);

    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      setError(message);
      setStatus('failed');
      setOutput((prev) => [
        ...prev,
        `\x1b[31m[Error starting Claude Code: ${message}]\x1b[0m\n`,
      ]);
    }
  }, [task, projectPath, buildPrompt, onComplete]);

  // Send input to PTY
  const handleSend = useCallback(async () => {
    if (!processIdRef.current || !input.trim()) return;

    try {
      await ptyWrite(processIdRef.current, input + '\n');
      setInput('');
    } catch (err) {
      console.error('Failed to send input:', err);
    }
  }, [input]);

  // Handle Enter key
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  // Stop/Cancel execution
  const handleStop = useCallback(async () => {
    if (processIdRef.current) {
      try {
        await ptyKill(processIdRef.current);
        setStatus('cancelled');
        setOutput((prev) => [
          ...prev,
          `\n\x1b[33m[Execution cancelled by user]\x1b[0m\n`,
        ]);
      } catch (err) {
        console.error('Failed to kill process:', err);
      }
    }
    processIdRef.current = null;
  }, []);

  // Close modal
  const handleClose = useCallback(() => {
    if (status === 'running' && processIdRef.current) {
      // Kill process before closing
      handleStop();
    }
    onClose();
  }, [status, handleStop, onClose]);

  if (!task) return null;

  const isRunning = status === 'running' || status === 'starting';
  const isFinished = status === 'success' || status === 'failed' || status === 'cancelled';

  return (
    <Modal
      isOpen={isOpen}
      onClose={handleClose}
      aria-label="Task Execution"
      variant="large"
      style={{ maxWidth: '900px' }}
    >
      <ModalHeader
        title={
          <Flex spaceItems={{ default: 'spaceItemsSm' }} alignItems={{ default: 'alignItemsCenter' }}>
            <FlexItem>
              <PlayIcon />
            </FlexItem>
            <FlexItem>
              Executing: {task.id}
            </FlexItem>
            <FlexItem>
              <Label
                color={
                  status === 'success' ? 'green' :
                  status === 'failed' ? 'red' :
                  status === 'cancelled' ? 'orange' :
                  status === 'running' ? 'blue' :
                  status === 'starting' ? 'teal' :
                  'grey'
                }
                icon={
                  status === 'success' ? <CheckCircleIcon /> :
                  status === 'failed' ? <ExclamationCircleIcon /> :
                  status === 'running' || status === 'starting' ? <Spinner size="sm" /> :
                  undefined
                }
              >
                {status}
              </Label>
            </FlexItem>
          </Flex>
        }
      />
      <ModalBody>
        {/* Error alert */}
        {error && (
          <Alert variant="danger" title="Execution Error" isInline style={{ marginBottom: '16px' }}>
            {error}
          </Alert>
        )}

        {/* Task info */}
        <div style={{ marginBottom: '16px' }}>
          <strong>Task:</strong> {task.description}
        </div>

        {/* Terminal output */}
        <div
          ref={outputRef}
          style={{
            height: '400px',
            backgroundColor: '#1e1e1e',
            color: '#d4d4d4',
            fontFamily: 'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace',
            fontSize: '13px',
            padding: '12px',
            overflowY: 'auto',
            whiteSpace: 'pre-wrap',
            borderRadius: '6px',
            marginBottom: '12px',
            border: '1px solid #333',
          }}
        >
          {output.map((line, i) => (
            <span key={i}>{line}</span>
          ))}
          {output.length === 0 && status === 'idle' && (
            <span style={{ color: '#888' }}>
              Click "Start" to begin executing this task with Claude Code...
            </span>
          )}
        </div>

        {/* Input field (only when running) */}
        {isRunning && (
          <Flex spaceItems={{ default: 'spaceItemsSm' }}>
            <FlexItem grow={{ default: 'grow' }}>
              <TextInput
                value={input}
                onChange={(_e, val) => setInput(val)}
                onKeyDown={handleKeyDown}
                placeholder="Type a message to Claude and press Enter..."
                aria-label="Input to Claude"
              />
            </FlexItem>
            <FlexItem>
              <Button variant="secondary" onClick={handleSend} isDisabled={!input.trim()}>
                Send
              </Button>
            </FlexItem>
          </Flex>
        )}

        {/* Process info */}
        {processInfo && (
          <div style={{ marginTop: '8px', fontSize: '12px', color: '#888' }}>
            <strong>Process ID:</strong> {processInfo.id} |{' '}
            <strong>CWD:</strong> {processInfo.cwd}
          </div>
        )}
      </ModalBody>
      <ModalFooter>
        {status === 'idle' && (
          <Button variant="primary" onClick={handleStart} icon={<PlayIcon />}>
            Start Execution
          </Button>
        )}
        {isRunning && (
          <Button variant="danger" onClick={handleStop} icon={<StopIcon />}>
            Stop
          </Button>
        )}
        {isFinished && (
          <Button variant="primary" onClick={handleClose}>
            Close
          </Button>
        )}
        {!isFinished && (
          <Button variant="link" onClick={handleClose}>
            Cancel
          </Button>
        )}
      </ModalFooter>
    </Modal>
  );
}

export default TaskExecutionModal;

